$(function(){var t={target:$("#player"),btnPlay:$(".player-play"),btnPaus:$(".player-paus"),btnBack:$(".player-back"),init:function(){this.btnPlay.on("click",function(){!1===t.target.get(0).paused?t.pause():t.play()}),this.target.on("ended",function(){t.back()}),this.btnBack.on("click",function(){t.back()})},play:function(){this.target.get(0).play(),this.btnPlay.attr("class","player-paus")},pause:function(){this.target.get(0).pause(),this.btnPlay.attr("class","player-play")},back:function(){this.target.get(0).pause(),this.target.get(0).currentTime=0,this.btnPlay.attr("class","player-play")}};t.init()});